115→                nn_vec_mat_mult_t_s16_s16_s16(in_lhs,
116→                                              in_rhs,
117→                                              lhs_offset,
118→                                              rhs_offset,
119→                                              bias,
120→                                              dst,
121→                                              out_offset,
122→                                              reduced_multiplier,
123→                                              out_shift,
124→                                              rhs_cols,
125→                                              rhs_rows,
126→                                              act_min,
127→                                              act_max);
128→                in_lhs += rhs_cols;
129→                dst += rhs_rows;
130→            }
131→            in_lhs -= inner_lhs_diff;
132→            in_rhs += inner_rhs_diff;
133→        }
134→        in_lhs += outer_lhs_diff;
135→        in_rhs += outer_rhs_diff;
136→    }
137→#endif
138→
139→    return 0;
140→}
