 22→int32_t nn_vec_mat_mult_t_s8(const q7_t *lhs,
 23→                             const q7_t *rhs,
 24→                             const q31_t *bias,
 25→                             q7_t *dst,
 26→                             const int32_t lhs_offset,   //value is in the range of [-127, 128]
 27→                             const int32_t rhs_offset,   //value is in the range of [-127, 128]
 28→                             const int32_t dst_offset,   //value is in the range of [-128, 127]
 29→                             const int32_t dst_multiplier,
 30→                             const int32_t dst_shift,
 31→                             const int32_t rhs_cols,
 32→                             const int32_t rhs_rows,
 33→                             const int32_t activation_min,
 34→                             const int32_t activation_max)
 35→{
 36→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 37→    long vl;
 38→    long dst_shift2 = 30 - dst_shift;
 39→
 40→    for (int32_t rhs_rows_idx = 0; rhs_rows_idx <= (rhs_rows - 2); rhs_rows_idx += 2)
 41→    {
 42→        const q7_t *lhs_ptr = &lhs[0];
 43→        const q7_t *rhs_ptr = &rhs[0];
 44→        const q7_t *rhs_ptr2 = &rhs[rhs_cols];
 45→        vl = __riscv_vsetvl_e32m8(rhs_cols);
 46→        vint32m8_t vResult1 = __riscv_vundefined_i32m8(),
 47→                   vResult2 = __riscv_vundefined_i32m8();
 48→        vResult1 = __riscv_vand(vResult1, 0, vl);     //for keeping 1st vwmacc results
 49→        vResult2 = __riscv_vand(vResult2, 0, vl);     //for keeping 2nd vwmacc results
 50→
 51→        long rhs_cols2 = rhs_cols;
 52→        while(rhs_cols2 > 0)
 53→        {
 54→            vl = __riscv_vsetvl_e8m2(rhs_cols2);
 55→            vint8m2_t vLhs_i8 = __riscv_vle8_v_i8m2(lhs_ptr, vl);                   //*lhs_ptr
 56→            vint8m2_t vRhs_i8 = __riscv_vle8_v_i8m2(rhs_ptr, vl);                   //*rhs_ptr
 57→            vint8m2_t vRhs2_i8 = __riscv_vle8_v_i8m2(rhs_ptr2, vl);                 //*rhs_ptr2
 58→            vl = __riscv_vsetvl_e16m4(rhs_cols2);
 59→            vint16m4_t vLhs_i16 = __riscv_vsext_vf2(vLhs_i8, vl);
 60→            vint16m4_t vRhs_i16 = __riscv_vsext_vf2(vRhs_i8, vl);
 61→            vint16m4_t vRhs2_i16 = __riscv_vsext_vf2(vRhs2_i8, vl);
 62→            vLhs_i16 = __riscv_vadd(vLhs_i16, lhs_offset, vl);    //*lhs_ptr + lhs_offset
 63→            vRhs_i16 = __riscv_vadd(vRhs_i16, rhs_offset, vl);    //*rhs_ptr + rhs_offset
 64→            vRhs2_i16 = __riscv_vadd(vRhs2_i16, rhs_offset, vl);  //*rhs_ptr2 + rhs_offset
 65→            vResult1 = __riscv_vwmacc(vResult1, vLhs_i16, vRhs_i16, vl);
 66→            vResult2 = __riscv_vwmacc(vResult2, vLhs_i16, vRhs2_i16, vl);
 67→            lhs_ptr += vl;
 68→            rhs_ptr += vl;
 69→            rhs_ptr2 += vl;
 70→            rhs_cols2 -= vl;
 71→        }
 72→
 73→        vl = __riscv_vsetvl_e32m1(1);
 74→        vint32m1_t vZero = __riscv_vundefined_i32m1();
 75→        vZero = __riscv_vand(vZero, 0, vl);
 76→
 77→        //note the avl here to make sure the length to be reducted into sum is correct
 78→        vl = __riscv_vsetvl_e32m8(rhs_cols);
 79→        vint32m1_t vRedsum1_i32 = __riscv_vundefined_i32m1();
 80→        vint32m1_t vRedsum2_i32 = __riscv_vundefined_i32m1();
 81→        vRedsum1_i32 = __riscv_vredsum(vResult1, vZero, vl);
 82→        vRedsum2_i32 = __riscv_vredsum(vResult2, vZero, vl);
 83→
 84→        vl = __riscv_vsetvl_e32m1(2);
 85→        vRedsum1_i32 = __riscv_vslideup(vRedsum1_i32, vRedsum2_i32, 1, vl);
 86→
 87→        if(bias != NULL)
 88→        {
 89→            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
 90→            vRedsum1_i32 = __riscv_vadd(vRedsum1_i32, vBias, vl);
 91→            bias += vl;
 92→        }
 93→
 94→        // re-quantize
 95→        vint64m2_t vWmul_r0 = __riscv_vwmul(vRedsum1_i32, dst_multiplier, vl);
 96→        vRedsum1_i32 = __riscv_vnsra(vWmul_r0, dst_shift2, vl);
 97→        vRedsum1_i32 = __riscv_vssra(vRedsum1_i32, 1, __RISCV_VXRM_RNU, vl);
 98→
 99→        vRedsum1_i32 = __riscv_vadd(vRedsum1_i32, dst_offset, vl);
100→
101→        // Clamp the result
102→        vRedsum1_i32 = __riscv_vmax(vRedsum1_i32, activation_min, vl);
103→        vRedsum1_i32 = __riscv_vmin(vRedsum1_i32, activation_max, vl);
104→
105→        //narrowing and store the results
106→        vl = __riscv_vsetvl_e16mf2(vl);
107→        vint16mf2_t vRedsum1_i16 = __riscv_vnsra(vRedsum1_i32, 0, vl);
108→        vl = __riscv_vsetvl_e8mf4(vl);
109→        vint8mf4_t vRedsum1_i8 = __riscv_vnsra(vRedsum1_i16, 0, vl);
110→        __riscv_vse8(dst, vRedsum1_i8, vl);
111→        dst += vl;
112→        rhs += 2 * rhs_cols;
113→    }
114→
115→    if (rhs_rows & 1)
116→    {
117→        const q7_t *lhs_ptr = &lhs[0];
118→        const q7_t *rhs_ptr = &rhs[0];
119→
120→        vl = __riscv_vsetvl_e32m1(1);
121→        vint32m1_t vBias = __riscv_vundefined_i32m1();
122→        vBias = __riscv_vand(vBias, 0, vl);
123→        if(bias != NULL)
124→        {
125→            vBias = __riscv_vle32_v_i32m1(bias, vl);
126→            bias++;
127→        }
128→        vl = __riscv_vsetvl_e32m8(rhs_cols);
129→        vint32m8_t vResult1 = __riscv_vundefined_i32m8();
130→        vResult1 = __riscv_vand(vResult1, 0, vl);     //for keeping vwmacc results
131→
132→        long rhs_cols2 = rhs_cols;
133→        while(rhs_cols2 > 0)
134→        {
135→            vl = __riscv_vsetvl_e8m2(rhs_cols2);
136→            vint8m2_t vRhs_i8 = __riscv_vle8_v_i8m2(rhs_ptr, vl);                    //*rhs_ptr
137→            vint8m2_t vLhs_i8 = __riscv_vle8_v_i8m2(lhs_ptr, vl);                    //*lhs_ptr
138→            vl = __riscv_vsetvl_e16m4(rhs_cols2);
139→            vint16m4_t vRhs_i16 = __riscv_vsext_vf2(vRhs_i8, vl);
140→            vint16m4_t vLhs_i16 = __riscv_vsext_vf2(vLhs_i8, vl);
141→            vRhs_i16 = __riscv_vadd(vRhs_i16, rhs_offset, vl);    //*rhs_ptr + rhs_offset
142→            vLhs_i16 = __riscv_vadd(vLhs_i16, lhs_offset, vl);    //*lhs_ptr + lhs_offset
143→            vResult1 = __riscv_vwmacc(vResult1, vRhs_i16, vLhs_i16, vl);
144→            rhs_ptr += vl;
145→            lhs_ptr += vl;
146→            rhs_cols2 -= vl;
147→        }
148→
149→        //note the avl here to make sure the length to be reducted into sum is correct
150→        vl = __riscv_vsetvl_e32m8(rhs_cols);

